class Solution:
    def maxStability(self, n: int, edges: List[List[int]], k: int) -> int:
        graph = [[] for _ in range(n)]
        for u, v, s, must in edges:
            graph[u].append((v, s, must))
            graph[v].append((u, s, must))

        def dfs(node, visited, upgrades):
            visited[node] = True
            max_strength = float('-inf')
            for neighbor, strength, must in graph[node]:
                if not visited[neighbor]:
                    max_strength = max(max_strength, dfs(neighbor, visited, upgrades))
                else:
                    max_strength = max(max_strength, strength)
            if upgrades > 0 and not must:
                max_strength = max(max_strength, 2 * max_strength)
                upgrades -= 1
            return max_strength

        max_stability = -1
        for i in range(n):
            visited = [False] * n
            max_stability = max(max_stability, dfs(i, visited, k))
        return max_stability
